#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long E, K;
        scanf("%lld %lld", &E, &K);
        int cnt = 0;
        while (E > 0) {
            cnt++;
            E /= K; // floor division for positive numbers
        }
        printf("%d\n", cnt);
    }
    return 0;
}

