#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        E = int(next(it))
        K = int(next(it))
        cnt = 0
        while E > 0:
            cnt += 1
            E //= K
        out_lines.append(str(cnt))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

